// Contact.js
import React from 'react';
import ContactForm from './ContactForm'; // Import the ContactForm component
import './Contact.css'; // Import the CSS for the Contact page

function Contact() {
  return (
    <div className="contact-page">
      <h1>Contact Me</h1>
      <p>If you have any questions, feel free to reach out using the form below.</p>
      <ContactForm />

      {/* Alternatively, reach me at section */}
      <div className="alternative-contact">
        <p>Alternatively, you can reach me at:</p>
        <div className="social-links">
          <a href="mailto:your-email@gmail.com" target="_blank" rel="noopener noreferrer">
            <img src="assets/gmail-icon.svg" alt="Gmail" className="icon" />
          </a>
          <a href="https://www.linkedin.com/in/your-profile/" target="_blank" rel="noopener noreferrer">
            <img src="assets/linkedin-icon.png" alt="LinkedIn" className="icon" />
          </a>
          <a href="https://www.instagram.com/your-profile/" target="_blank" rel="noopener noreferrer">
            <img src="assets/instagram-icon.png" alt="Instagram" className="icon" />
          </a>
        </div>
      </div>
    </div>
  );
}

export default Contact;
